return items.map(item => {
  const raw = item.json.contato || ''; // substitua "contato" se o nome do campo for outro
  const telefone = raw.split('@')[0]; // separa no "@" e pega a primeira parte
  return {
    json: {
      ...item.json,
      Telefone: telefone
    }
  };
});

